import{_ as i,C as s,o as n,c as d,j as r,a,E as o,ai as l}from"./chunks/framework.-fuqNImP.js";const k=JSON.parse('{"title":"First Playwright Tests","description":"","frontmatter":{},"headers":[],"relativePath":"courses/first-playwright-tests.md","filePath":"courses/first-playwright-tests.md"}'),h={name:"courses/first-playwright-tests.md"};function c(u,e,p,g,f,m){const t=s("Badge");return n(),d("div",null,[e[0]||(e[0]=r("h1",{id:"first-playwright-tests",tabindex:"-1"},[a("First Playwright Tests "),r("a",{class:"header-anchor",href:"#first-playwright-tests","aria-label":'Permalink to "First Playwright Tests"'},"​")],-1)),o(t,{type:"tip",text:"Beginner"}),e[1]||(e[1]=a()),o(t,{type:"info",text:"10 Modules"}),e[2]||(e[2]=a()),o(t,{type:"tip",text:"Complete"}),e[3]||(e[3]=l('<p>The recommended starting point for manual testers. Each lesson builds on the previous — from watching a test run to building your own test pack. No prior coding experience required.</p><h2 id="course-overview" tabindex="-1">Course Overview <a class="header-anchor" href="#course-overview" aria-label="Permalink to &quot;Course Overview&quot;">​</a></h2><p>This course teaches the <strong>Record → Refine → Review</strong> workflow that turns acceptance criteria into automated Playwright tests. You&#39;ll use GitHub Copilot to write code and the practice app as your test target.</p><div class="tip custom-block"><p class="custom-block-title">Who Is This For?</p><p>Manual QA testers who are excellent at finding bugs but new to writing test automation code. If you can read a test plan, you can learn this.</p></div><h2 id="module-breakdown" tabindex="-1">Module Breakdown <a class="header-anchor" href="#module-breakdown" aria-label="Permalink to &quot;Module Breakdown&quot;">​</a></h2><h3 id="_1-see-a-test-do-real-work" tabindex="-1">1. See a Test Do Real Work <a class="header-anchor" href="#_1-see-a-test-do-real-work" aria-label="Permalink to &quot;1. See a Test Do Real Work&quot;">​</a></h3><p>Watch an automated test run against the practice app. Understand what happens at each step — navigation, interaction, assertion — and why it matters.</p><h3 id="_2-just-enough-typescript-and-tooling" tabindex="-1">2. Just Enough TypeScript and Tooling <a class="header-anchor" href="#_2-just-enough-typescript-and-tooling" aria-label="Permalink to &quot;2. Just Enough TypeScript and Tooling&quot;">​</a></h3><p>The minimum TypeScript you need to read and modify tests. Variables, types, async/await, and the VS Code features that help.</p><h3 id="_3-set-up-the-workbench" tabindex="-1">3. Set Up the Workbench <a class="header-anchor" href="#_3-set-up-the-workbench" aria-label="Permalink to &quot;3. Set Up the Workbench&quot;">​</a></h3><p>Install Node.js, VS Code extensions, Playwright browsers. Configure your development environment so everything works on first run.</p><h3 id="_4-run-tests-from-vs-code-and-terminal" tabindex="-1">4. Run Tests from VS Code and Terminal <a class="header-anchor" href="#_4-run-tests-from-vs-code-and-terminal" aria-label="Permalink to &quot;4. Run Tests from VS Code and Terminal&quot;">​</a></h3><p>Two ways to run tests: the Playwright VS Code extension (click to run) and the terminal (<code>npx playwright test</code>). Learn when to use each.</p><h3 id="_5-read-a-test-like-evidence" tabindex="-1">5. Read a Test Like Evidence <a class="header-anchor" href="#_5-read-a-test-like-evidence" aria-label="Permalink to &quot;5. Read a Test Like Evidence&quot;">​</a></h3><p>Interpret test output, HTML reports, and trace files. Understand what passed, what failed, and why — the skills that make test results actionable.</p><h3 id="_6-find-the-right-element" tabindex="-1">6. Find the Right Element <a class="header-anchor" href="#_6-find-the-right-element" aria-label="Permalink to &quot;6. Find the Right Element&quot;">​</a></h3><p>Locator strategies — <code>getByTestId</code>, <code>getByRole</code>, <code>getByLabel</code>, <code>getByText</code>. When to use each, and why <code>data-testid</code> is the foundation.</p><h3 id="_7-ask-copilot-for-a-useful-draft" tabindex="-1">7. Ask Copilot for a Useful Draft <a class="header-anchor" href="#_7-ask-copilot-for-a-useful-draft" aria-label="Permalink to &quot;7. Ask Copilot for a Useful Draft&quot;">​</a></h3><p>Write prompts that produce useful test code. Structure your request with context, action, and expected outcome. Refine the output.</p><h3 id="_8-record-a-login-flow-in-vs-code" tabindex="-1">8. Record a Login Flow in VS Code <a class="header-anchor" href="#_8-record-a-login-flow-in-vs-code" aria-label="Permalink to &quot;8. Record a Login Flow in VS Code&quot;">​</a></h3><p>Use Playwright&#39;s codegen tool to record browser interactions. Walk through the login flow and capture it as executable test code.</p><h3 id="_9-tighten-and-re-run-the-recording" tabindex="-1">9. Tighten and Re-Run the Recording <a class="header-anchor" href="#_9-tighten-and-re-run-the-recording" aria-label="Permalink to &quot;9. Tighten and Re-Run the Recording&quot;">​</a></h3><p>Transform rough recorded code into a reliable test. Add assertions, replace selectors, remove noise, and verify the test catches real bugs.</p><h3 id="_10-build-your-first-test-pack" tabindex="-1">10. Build Your First Test Pack <a class="header-anchor" href="#_10-build-your-first-test-pack" aria-label="Permalink to &quot;10. Build Your First Test Pack&quot;">​</a></h3><p>Combine everything into a test suite. Write tests for multiple pages, organize them logically, and run the full pack.</p><h2 id="what-you-ll-build" tabindex="-1">What You&#39;ll Build <a class="header-anchor" href="#what-you-ll-build" aria-label="Permalink to &quot;What You&#39;ll Build&quot;">​</a></h2><p>By the end of this course, you&#39;ll have:</p><ul><li>A working Playwright test suite covering the practice app&#39;s login, products, and contact pages</li><li>Familiarity with VS Code&#39;s Playwright integration</li><li>Experience using Copilot to draft and refine test code</li><li>A reference test pack you can adapt for real projects</li></ul><h2 id="skills-progression" tabindex="-1">Skills Progression <a class="header-anchor" href="#skills-progression" aria-label="Permalink to &quot;Skills Progression&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Skill Gained</th><th>Practice App Pages</th></tr></thead><tbody><tr><td>1–3</td><td>Environment &amp; tooling</td><td>— (setup)</td></tr><tr><td>4–5</td><td>Running &amp; reading tests</td><td>All pages</td></tr><tr><td>6</td><td>Element selection</td><td>Products, Contact</td></tr><tr><td>7</td><td>Copilot prompting</td><td>Login, Products</td></tr><tr><td>8–9</td><td>Recording &amp; refining</td><td>Login</td></tr><tr><td>10</td><td>Full test authoring</td><td>Multiple pages</td></tr></tbody></table><h2 id="reference-tests" tabindex="-1">Reference Tests <a class="header-anchor" href="#reference-tests" aria-label="Permalink to &quot;Reference Tests&quot;">​</a></h2><p>After completing this course, compare your tests against the reference specs in <code>test-cases/examples/</code>:</p><table tabindex="0"><thead><tr><th>Spec File</th><th>Tests</th><th>Pages Covered</th></tr></thead><tbody><tr><td><code>login.spec.ts</code></td><td>7</td><td>Login</td></tr><tr><td><code>search.spec.ts</code></td><td>7</td><td>Products</td></tr><tr><td><code>contact.spec.ts</code></td><td>7</td><td>Contact</td></tr><tr><td><code>checkout.spec.ts</code></td><td>6</td><td>Checkout (4 steps)</td></tr></tbody></table><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing this course:</p><ul><li><a href="/midnight-automation-voyage/courses/copilot-first-testing">Copilot-First Testing</a> — deeper dive into AI-assisted testing workflow</li><li><a href="/midnight-automation-voyage/courses/build-skills">Build Skills</a> — page objects, API testing, CI/CD integration</li></ul>',36))])}const w=i(h,[["render",c]]);export{k as __pageData,w as default};
